module top_module(
    input A,
    input B,
    output SUM,
    output CARRY_OUT
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // XOR gate for SUM
    assign SUM = A ^ B;

    // AND gate for CARRY_OUT
  wire temp1_A = A;
  wire temp2_B = B;
  assign CARRY_OUT = temp1_A & temp2_B;

endmodule
